-- ============================================
-- Legislacao full-site: joao-campos / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/204429
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = joao-campos-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 26
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=204429, tipo Deputado(a), ordemAssinatura=1.
-- 74 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'joao-campos';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'joao-campos: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao joao-campos: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2259187', '2262332', '2259803', '2257462', '2256640', '2260865', '2258618', '2256180', '2255983', '2255635', '2256208', '2255984', '2255566', '2256424', '2256149', '2255633', '2255365', '2254898', '2257025', '2256138', '2254814', '2255582', '2260872', '2260625', '2258718', '2258339');
  IF target_present <> 26 THEN
    RAISE EXCEPTION 'Pre-condicao joao-campos: esperadas 26 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2259187', '2262332', '2259803', '2257462', '2256640', '2260865', '2258618', '2256180', '2255983', '2255635', '2256208', '2255984', '2255566', '2256424', '2256149', '2255633', '2255365', '2254898', '2257025', '2256138', '2254814', '2255582', '2260872', '2260625', '2258718', '2258339')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'joao-campos-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao joao-campos: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao joao-campos: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

